parameters.jsCode:
const results = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  let orgItem;
  try {
    orgItem = $('Parse Organizations').all()[i].json;
  } catch (e) {
    console.error('Could not get organization details:', e.message);
  }
  const orgId = orgItem ? orgItem.id : '';

  const channels = item.json.data?.channels || [];
  for (const channel of channels) {
    results.push({
      json: {
        id: channel.id,
        name: channel.name,
        service: channel.service,
        organization_id: orgId
      }
    });
  }
}
return results;

