parameters.jsCode:
const results = [];
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  const item = items[i];
  let channelItem;
  try {
    channelItem = $('Parse Channels').all()[i].json;
  } catch (e) {
    console.error('Could not get channel details:', e.message);
  }
  const channelId = channelItem ? channelItem.id : '';

  const edges = item.json.data?.posts?.edges || [];
  for (const edge of edges) {
    const post = edge.node;
    if (post) {
      results.push({
        json: {
          id: post.id,
          text: post.text || '',
          channel_id: channelId,
          due_at: post.dueAt ? new Date(post.dueAt).toISOString() : null,
          status: post.status || 'unknown',
          assets: [],
          metrics: post.metrics || []
        }
      });
    }
  }
}
return results;
